'use strict';

const fs = require('fs');
const path = require('path');
const { allProducts } = require('../core/products.js');
const config = require('../config.js');
const { AppError } = require('../lib/errors.js');

function exportProducts(args) {
  const formatIndex = args.indexOf('--format');
  if (formatIndex === -1 || formatIndex + 1 >= args.length) {
    throw new AppError('usage: export-products --format <csv|json>', 2);
  }
  const format = args[formatIndex + 1];
  if (format !== 'csv' && format !== 'json') {
    throw new AppError('unsupported format: ' + format, 2);
  }

  fs.mkdirSync(config.outputDir, { recursive: true });

  const filepath = path.join(config.outputDir, 'products.' + format);
  let content;

  if (format === 'csv') {
    const products = allProducts();
    const lines = ['id,name,price'];
    for (const p of products) {
      lines.push(p.id + ',' + p.name + ',' + p.price.toFixed(2));
    }
    content = lines.join('\n') + '\n';
  } else {
    content = JSON.stringify(allProducts(), null, 2);
  }

  fs.writeFileSync(filepath, content);

  return ['exported products to ' + filepath];
}

module.exports = { exportProducts };

